// 世界引擎 · 全局主题样式（纯 CSS 字符串，注入弹窗 iframe head）
// 「墨卷山河」— 古风黑暗：极墨深底、宣纸暖白、朱砂血色、古铜金线

export const 主题样式 = `
@import url('https://fonts.googleapis.com/css2?family=Ma+Shan+Zheng&display=swap');
@import url('https://fontsapi.zeoseven.com/183/main/result.css');

:root {
  font-size: 17px;

  /* ═══ 墨阶 ═══ */
  --c-bg: #07090a;            /* 极墨底 */
  --c-bg-deep: #040506;       /* 更深 */
  --c-panel: #0f1214;         /* 面板底 */
  --c-panel-raised: #161a1e;  /* 抬升面板 */
  --c-panel-hover: #1e2328;   /* 悬停 */

  /* ═══ 宣纸文字 ═══ */
  --c-text: #ede8dd;          /* 主文字：明亮暖白 */
  --c-text-dim: #b5ad9e;      /* 次要：中灰 */
  --c-text-mid: #9a9386;      /* 中间态 */
  --c-text-faint: #6a645a;    /* 弱化但仍可读 */
  --c-text-ghost: #4a4640;    /* 装饰性 */

  /* ═══ 朱砂血色 ═══ */
  --c-accent: #d45650;
  --c-accent-bright: #e8706a;
  --c-accent-glow: rgba(212, 86, 80, 0.45);
  --c-accent-dim: rgba(212, 86, 80, 0.15);

  /* ═══ 古铜金 ═══ */
  --c-bronze: #c9a05c;
  --c-bronze-light: #ddb876;
  --c-bronze-dim: rgba(201, 160, 92, 0.22);

  /* ═══ 朱砂印 ═══ */
  --c-stamp: #9a2828;
  --c-stamp-bright: #c43a3a;

  /* ═══ 边框 ═══ */
  --c-border: rgba(201, 160, 92, 0.12);
  --c-border-mid: rgba(201, 160, 92, 0.22);
  --c-border-strong: rgba(201, 160, 92, 0.38);
  --c-border-blood: rgba(212, 86, 80, 0.42);
  --c-hairline: rgba(237, 232, 221, 0.03);

  /* ═══ 势力四色 ═══ */
  --c-faction-正道: #5a9a72;
  --c-faction-魔道: #d45650;
  --c-faction-古神: #9a6aba;
  --c-faction-其他: #c9a05c;

  /* 与开场一致：正文使用极影毁片辉宋，书法标题使用 Ma Shan Zheng。 */
  --font-serif: '极影毁片辉宋 Bold', 'STKaiti', 'KaiTi', 'FangSong', 'Songti SC', 'SimSun', serif;
  --font-ui: '极影毁片辉宋 Bold', 'STKaiti', 'KaiTi', 'FangSong', 'Songti SC', 'SimSun', serif;
  --font-brush: 'Ma Shan Zheng', 'ZCOOL KuaiLe', '华文行楷', 'STXingkai', '华文新魏', 'STXinwei', '华文隶书', 'STLiti', 'KaiTi', 'STKaiti', serif;

  --radius-xs: 2px;
  --radius-sm: 4px;
  --radius-md: 6px;
  --radius-pill: 999px;

  --ease-out-soft: cubic-bezier(.22,.61,.36,1);
}

/* 确保 iframe 内部视口链正确，使 .we-root 的 height:100% 生效 */
html, body { height: 100%; margin: 0; overflow: hidden; }
html { scroll-behavior: smooth; }

.we-root, .we-root * { box-sizing: border-box; }

/* 全局顺滑：交互元素统一缓动曲线与时长 */
.we-root button,
.we-root input,
.we-root select,
.we-root .we-card,
.we-root [class*="card"],
.we-root [class*="btn"] {
  transition-timing-function: var(--ease-out-soft);
}

/* ═══ 墨卷底 ═══
   深墨 + 微噪纹理 + 顶部淡金晕染 + 四边暗角 */
.we-root {
  background:
    /* 顶部暖光晕染 */
    radial-gradient(ellipse 90% 50% at 50% 0%, rgba(201, 160, 92, 0.04) 0%, transparent 55%),
    /* 右下角淡红晕染 */
    radial-gradient(ellipse 60% 40% at 100% 100%, rgba(212, 86, 80, 0.03) 0%, transparent 50%),
    /* 全局暗角 */
    radial-gradient(ellipse 140% 140% at 50% 50%, transparent 50%, rgba(0,0,0,0.55) 100%),
    /* 主渐变 */
    linear-gradient(175deg, #0d1012 0%, var(--c-bg) 40%, var(--c-bg-deep) 100%);
  color: var(--c-text);
  font-family: var(--font-serif);
  position: relative;
  isolation: isolate;
  contain: layout paint;
}

/* 浏览器表单控件默认不继承字体，显式与开场正文保持一致。 */
.we-root button,
.we-root input,
.we-root select,
.we-root textarea {
  font-family: var(--font-serif);
}

.we-root button,
.we-root input,
.we-root select,
.we-root textarea {
  touch-action: manipulation;
}

/* 轻量纸纹：用纯渐变替代 feTurbulence，避免全屏 SVG 滤镜持续占用栅格资源。 */
.we-root::before {
  content: '';
  position: absolute;
  inset: 0;
  opacity: 0.12;
  pointer-events: none;
  background-image:
    repeating-linear-gradient(0deg, transparent 0 3px, rgba(255,255,255,0.012) 3px 4px),
    repeating-linear-gradient(90deg, transparent 0 5px, rgba(0,0,0,0.025) 5px 6px);
  background-repeat: repeat;
  background-size: 17px 19px, 23px 29px;
  z-index: 0;
}

/* 长列表只栅格化视口附近的卡片；不支持该属性的浏览器会自然回退。 */
.faction-card,
.npc-card,
.region-card,
.uc-card,
.tl-entry,
.set-section {
  content-visibility: auto;
  contain-intrinsic-size: auto 150px;
}

.we-content {
  overscroll-behavior: contain;
  -webkit-overflow-scrolling: touch;
  scrollbar-gutter: stable;
}

.we-tabs {
  overscroll-behavior-x: contain;
  scrollbar-width: none;
  touch-action: pan-x;
}
.we-tabs::-webkit-scrollbar { display: none; }

/* ═══ 滚动条 ═══ */
.we-root ::-webkit-scrollbar { width: 5px; height: 5px; }
.we-root ::-webkit-scrollbar-track { background: transparent; }
.we-root ::-webkit-scrollbar-thumb {
  background: linear-gradient(180deg, var(--c-bronze-dim), rgba(201,160,92,0.4));
  border-radius: var(--radius-pill);
}
.we-root ::-webkit-scrollbar-thumb:hover { background: var(--c-accent); }

/* ═══ 通用卡片基础 ═══ */
.we-card {
  background: linear-gradient(165deg, var(--c-panel-raised) 0%, var(--c-panel) 100%);
  border: 1px solid var(--c-border);
  border-radius: var(--radius-sm);
  transition: border-color 0.25s ease, box-shadow 0.25s ease;
}
.we-card:hover {
  border-color: var(--c-border-mid);
  box-shadow: 0 2px 12px rgba(0,0,0,0.3), inset 0 1px 0 rgba(201,160,92,0.04);
}

/* ═══ 古风分割线 ═══ */
.we-divider {
  height: 1px;
  background: linear-gradient(90deg,
    transparent 0%,
    var(--c-border-mid) 15%,
    var(--c-border-strong) 50%,
    var(--c-border-mid) 85%,
    transparent 100%
  );
}

/* ═══ 角花装饰 ═══ */
.we-corner {
  position: relative;
}
.we-corner::before,
.we-corner::after {
  content: '';
  position: absolute;
  width: 8px;
  height: 8px;
  border-color: var(--c-border-strong);
  border-style: solid;
  pointer-events: none;
}
.we-corner::before {
  top: -1px; left: -1px;
  border-width: 1px 0 0 1px;
}
.we-corner::after {
  bottom: -1px; right: -1px;
  border-width: 0 1px 1px 0;
}

/* ═══ 窄屏自适应（手机）═══ */
/* 弹窗 iframe 在窄屏下接近全屏，内部整体收窄留白、压小字号，并让所有双列网格降为单列 */
@media (max-width: 599px) {
  :root { font-size: 15px; }
  .we-header {
    padding-top: max(10px, env(safe-area-inset-top)) !important;
    padding-right: max(12px, env(safe-area-inset-right)) !important;
    padding-bottom: 10px !important;
    padding-left: max(12px, env(safe-area-inset-left)) !important;
  }
  .we-title { gap: 9px !important; min-width: 0; }
  .we-stamp { width: 34px !important; height: 34px !important; box-shadow: none !important; }
  .we-title-main { font-size: 1.05rem; letter-spacing: 0.18em; }
  .we-title-sub { display: none; }
  .we-header-actions { gap: 6px; }
  .we-btn-primary { min-height: 40px; padding: 8px 11px !important; font-size: 0.82rem !important; }
  .we-btn-icon { width: 40px !important; height: 40px !important; }
  .we-tabs {
    padding-right: max(6px, env(safe-area-inset-right)) !important;
    padding-left: max(6px, env(safe-area-inset-left)) !important;
  }
  .we-tab-btn { min-height: 44px; padding: 9px 11px !important; font-size: 0.82rem !important; gap: 4px !important; }
  .we-content {
    padding-top: 12px !important;
    padding-right: max(12px, env(safe-area-inset-right)) !important;
    padding-bottom: max(12px, env(safe-area-inset-bottom)) !important;
    padding-left: max(12px, env(safe-area-inset-left)) !important;
  }
  /* 饼图区：纵向堆叠 */
  .pie-wrap { flex-direction: column !important; gap: 14px !important; padding: 14px !important; align-items: stretch !important; }
  .pie { width: 150px !important; height: 150px !important; align-self: center; }

  /* 所有双列卡片网格 → 单列 */
  .faction-group .faction-cards,
  .we-page { grid-template-columns: 1fr !important; }

  .set-section { padding: 14px 14px; }
  .api-mode-switch { grid-template-columns: 1fr !important; }
  .set-field input, .set-field select { min-height: 44px; font-size: 1rem !important; }
  .set-btn, .npc-add-btn, .bond-refresh { min-height: 40px; }
  .npc-del { min-width: 40px !important; height: 40px !important; }
  .model-row { flex-wrap: wrap; }
  .model-row select { min-width: 100%; }
  .model-row .set-btn { margin-left: auto; }
  .atm-box { align-items: flex-start !important; flex-wrap: wrap; }
  .atm-text { flex-basis: 100%; line-height: 1.6; }
  .fc-head, .fc-foot, .region-head, .npc-meta { flex-wrap: wrap; }

  /* 时间线：窄屏改为单侧排列，避免卡片过窄 */
  .tl-entry.left, .tl-entry.right { padding-left: 0 !important; padding-right: 0 !important; padding-left: 26px !important; }
  .timeline-line { left: 8px !important; transform: none !important; }
  .tl-node { left: 8px !important; }
  .taiji { animation: none !important; }
}

@media (max-width: 359px) {
  .we-title-main { font-size: 0.92rem; letter-spacing: 0.1em; }
  .we-btn-primary span { display: none; }
  .we-btn-primary { width: 40px; padding: 0 !important; justify-content: center; }
}

/* 触屏设备不保留桌面悬停位移，避免点击后卡片悬浮和阴影重绘。 */
@media (hover: none) {
  .faction-card:hover,
  .npc-card:hover,
  .region-card:hover,
  .uc-card:hover,
  .tl-card:hover,
  .bond-person:hover,
  .set-btn:hover,
  .we-btn-primary:hover {
    transform: none !important;
  }
}

@media (prefers-reduced-motion: reduce) {
  html { scroll-behavior: auto; }
  .we-root *,
  .we-root *::before,
  .we-root *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}
`;
