// 世界引擎 · 主线剧情摘要
// 监听 tavern_events.MESSAGE_RECEIVED，每「摘要间隔」楼把旧摘要与最新楼层重写为新的滚动摘要。
// 新摘要完整替代旧摘要，永久硬限制 200 字；剧情模式同时为本周目时间线追加一条 100 字经历。

import { jsonrepair } from 'jsonrepair';
import { 规范主线摘要, 规范周目经历, type 世界引擎 } from './schema';
import { 读取主线状态 } from './主线状态';

let 摘要中 = false;

function 摘要提示词(记录周目经历: boolean): string {
  const 经历要求 = 记录周目经历
    ? '2. 「新增经历」只概括【最新楼层原文】中本阶段真正发生的行动、转折、关系变化与结果，作为永久时间线节点；不要复述旧摘要，信息不足也不要编造。含标点严格不超过100字。'
    : '2. 当前为沙盒模式，不维护「本周目经历」；「新增经历」必须输出空字符串。';
  return `你负责同时维护「近期滚动摘要」和「本周目经历时间线」。请把【旧滚动摘要】与【最新楼层原文】处理成两个不同结果。

要求：
1. 「近期摘要」由旧摘要与最新原文合并重写，只保留当前时间地点、仍影响当下的人物、未解决目标/危险和最新状态；已解决或被取代的旧情节删除。含标点严格不超过200字。
${经历要求}
3. 只记录明确发生的事实，不补写动机，不替主角决定，不默认主角是修士。忽略修辞、闲聊、重复战斗过程和重复性色情细节。
4. 严格区分秩序侧古神、外神奈亚与旧日支配者；污染和梦魇优先归因于旧日支配者或残响。
5. 角色卡状态仅校正姓名、身份、当前时间地点；不得把整份状态抄入摘要。若旧摘要与最新原文冲突，以最新原文和角色卡为准。
6. 只输出一行合法 JSON，不要代码块、标题或说明，格式必须是：{"近期摘要":"...","新增经历":"..."}`;
}

function 解析摘要结果(text: string): { 近期摘要: string; 新增经历: string } {
  const cleaned = text
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  try {
    const parsed = JSON.parse(jsonrepair(cleaned)) as Record<string, unknown>;
    return {
      近期摘要: 规范主线摘要(String(parsed.近期摘要 ?? '')),
      新增经历: 规范周目经历(String(parsed.新增经历 ?? '')),
    };
  } catch (error) {
    console.warn('[世界引擎] 摘要 JSON 解析失败，降级为纯文本摘要', error);
    return {
      近期摘要: 规范主线摘要(cleaned),
      新增经历: 规范周目经历(cleaned),
    };
  }
}

function 下一个经历序号(engine: 世界引擎): string {
  const indexes = Object.keys(engine.周目.经历)
    .map(value => Number(value))
    .filter(Number.isFinite);
  return String((indexes.length ? Math.max(...indexes) : 0) + 1);
}

// 取从 start 楼到当前最新楼层的原文，拼成字符串
function 取近期楼层原文(start: number): string {
  const last = getLastMessageId();
  if (start > last) return '（无新楼层）';
  const msgs = getChatMessages(`${start}-${last}`, { role: 'all' });
  return msgs
    .filter(m => m.role === 'user' || m.role === 'assistant')
    .map(m => `[${m.role === 'user' ? '主角' : '世界'}] ${m.message}`)
    .join('\n\n');
}

// 生成摘要：传入当前世界引擎数据（含配置），返回是否执行了生成
export async function 生成摘要(engine: 世界引擎): Promise<boolean> {
  if (摘要中) return false;
  if (engine.周目?.状态 === '已完成') return false;
  const 配置 = engine.配置;
  if (!配置?.自动摘要) return false;
  const 上次楼层 = engine.摘要?.上次摘要楼层 ?? 0;
  const 本次起始楼层 = Math.max(上次楼层, engine.周目.上次经历楼层) + 1;
  const 间隔 = 配置?.摘要间隔 ?? 5;
  const last = getLastMessageId();
  if (last - 上次楼层 < 间隔) return false;

  摘要中 = true;
  try {
    const 原文 = 取近期楼层原文(上次楼层 + 1);
    const api = 配置?.custom_api ?? null;
    const custom_api =
      api && api.apiurl && api.model
        ? { custom_api: { source: api.source, apiurl: api.apiurl, key: api.key || undefined, model: api.model } }
        : {};

    const 主线状态 = 读取主线状态();
    const 记录周目经历 = 主线状态?.游戏模式 !== '沙盒模式';
    const 旧摘要 = 规范主线摘要(engine.摘要?.近期摘要 ?? '');
    const rawResult = await generateRaw({
      should_silence: true,
      ...custom_api,
      ordered_prompts: [
        { role: 'system', content: 摘要提示词(记录周目经历) },
        { role: 'system', content: `【角色卡当前状态（仅校正）】${JSON.stringify(主线状态 ?? null)}` },
        { role: 'system', content: `【旧滚动摘要】${旧摘要 || '（无）'}` },
        { role: 'system', content: `【最新楼层原文】\n${原文}` },
        {
          role: 'user',
          content: 记录周目经历
            ? '生成近期摘要与本阶段经历，严格按单行 JSON 输出。'
            : '只生成近期摘要；新增经历必须为空字符串。严格按单行 JSON 输出。',
        },
      ],
    } as any);
    const result = typeof rawResult === 'string' ? rawResult : rawResult.content;
    if (!result) return false;
    const { 近期摘要, 新增经历 } = 解析摘要结果(result);

    engine.摘要 = {
      近期摘要,
      上次摘要楼层: last,
    };
    if (记录周目经历 && 新增经历) {
      engine.周目.经历[下一个经历序号(engine)] = {
        起始楼层: Math.max(0, 本次起始楼层),
        结束楼层: last,
        内容: 新增经历,
      };
    }
    engine.周目.上次经历楼层 = last;

    // 写回聊天变量
    const variables = getVariables({ type: 'chat' });
    _.set(variables, '世界引擎', engine);
    replaceVariables(variables, { type: 'chat' });

    console.info(
      `[世界引擎] 摘要已更新${记录周目经历 ? '，并追加周目经历' : '（沙盒模式，不记录周目经历）'}（截至第 ${last} 楼）`,
    );
    return true;
  } catch (e) {
    console.error('[世界引擎] 摘要生成失败', e);
    return false;
  } finally {
    摘要中 = false;
  }
}

// 自动推进检查：达到间隔且开启自动推进时触发推进
export async function 检查自动推进(engine: 世界引擎): Promise<boolean> {
  if (engine.周目?.状态 === '已完成') return false;
  const 配置 = engine.配置;
  if (!配置?.自动推进) return false;
  const 上次推进 = engine.上次推进楼层 ?? 0;
  const 间隔 = 配置.自动推进间隔 ?? 10;
  const last = getLastMessageId();
  if (last - 上次推进 < 间隔) return false;
  return true;
}
