import { jsonrepair } from 'jsonrepair';
import { ref } from 'vue';
import type { 世界引擎 } from './schema';
import { 读取主线状态 } from './主线状态';
import {
  保存周目档案,
  周目档案Schema,
  构建MVU继承快照,
  规范人物志,
  规范周目内容,
  规范周目标题,
  规范周目结局,
  type 周目档案,
  type 轮回人物候选,
} from './轮回';

export interface 周目总结草稿 {
  标题: string;
  内容: string;
  结局: string;
  人物志: Record<string, string>;
}

export const 周目总结中 = ref(false);

function 读取未归档楼层(engine: 世界引擎): string {
  const start = Math.max(engine.周目.上次经历楼层, engine.摘要.上次摘要楼层) + 1;
  const last = getLastMessageId();
  if (start > last) return '（无）';
  return getChatMessages(`${start}-${last}`, { role: 'all' })
    .filter(message => message.role === 'user' || message.role === 'assistant')
    .map(message => `[${message.role === 'user' ? '主角' : '世界'}] ${message.message}`)
    .join('\n\n');
}

function 构建custom_api(engine: 世界引擎): Record<string, unknown> {
  const api = engine.配置?.custom_api;
  return api?.apiurl && api.model
    ? { custom_api: { source: api.source, apiurl: api.apiurl, key: api.key || undefined, model: api.model } }
    : {};
}

function 解析总结(text: string): 周目总结草稿 {
  const cleaned = text
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  const parsed = JSON.parse(jsonrepair(cleaned)) as Record<string, unknown>;
  const people =
    parsed.人物志 && typeof parsed.人物志 === 'object' && !Array.isArray(parsed.人物志)
      ? _.mapValues(parsed.人物志 as Record<string, unknown>, value => 规范人物志(value))
      : {};
  const draft = {
    标题: 规范周目标题(parsed.标题),
    内容: 规范周目内容(parsed.内容),
    结局: 规范周目结局(parsed.结局),
    人物志: people,
  };
  if (!draft.内容 || !draft.结局) throw new Error('模型未返回完整的周目内容与结局');
  return draft;
}

export async function 生成周目总结(engine: 世界引擎, selected: readonly 轮回人物候选[]): Promise<周目总结草稿> {
  if (周目总结中.value) throw new Error('周目总结正在生成中');
  if (engine.周目.状态 === '已完成') throw new Error('本周目已经封存');
  周目总结中.value = true;

  try {
    const experiences = Object.entries(engine.周目.经历)
      .sort(([a], [b]) => Number(a) - Number(b))
      .map(([index, item]) => `${index}. 第${item.起始楼层}-${item.结束楼层}楼：${item.内容}`)
      .join('\n');
    const people = selected.map(person => ({
      名称: person.名称,
      类型: person.类型,
      继承方式: person.继承方式,
      关系: person.关系,
      好感度: person.好感度,
      身份: person.身份,
      现有摘要: person.摘要,
    }));
    const prompt = `你负责为一段已经结束的修仙轮回生成可供下一周目继承的正式档案。

要求：
1. 标题不超过24字，像游戏周目章节名。
2. 内容以明确事实串联本周目的开端、关键选择、重要转折、关系变化与最终结果，400~600字；不得发明经历中没有的事件。
3. 结局用80~120字说明主角与世界最终处境，以及轮回为何结束。
4. 为每名指定继承人物写不超过150字的人物志，包含身份、与主角的核心关系、一项共同经历或承诺，以及下一周目的继承表现；不得写数值清单。
5. 「前世回响」表示新时间线同位体产生梦境或既视感；「轮回同行」表示原本灵魂随主角而来；「神契随行」表示借神契跨越轮回。
6. 只输出一行合法JSON，不要代码块或说明。格式：{"标题":"...","内容":"...","结局":"...","人物志":{"人物名":"..."}}`;

    const raw = await generateRaw({
      should_silence: true,
      ...构建custom_api(engine),
      ordered_prompts: [
        { role: 'system', content: prompt },
        { role: 'system', content: `【本周目编号】${engine.周目.编号}` },
        { role: 'system', content: `【近期摘要】${engine.摘要.近期摘要 || '（无）'}` },
        {
          role: 'system',
          content: `【本周目经历】\n${experiences || '（没有自动经历记录，请仅依据近期摘要与最终状态）'}`,
        },
        { role: 'system', content: `【尚未进入自动经历的最新楼层】\n${读取未归档楼层(engine)}` },
        { role: 'system', content: `【最终人物与世界状态】${JSON.stringify(读取主线状态())}` },
        { role: 'system', content: `【指定继承人物】${JSON.stringify(people)}` },
        { role: 'user', content: '生成本周目的正式档案与指定人物志。' },
      ],
    } as any);
    const text = typeof raw === 'string' ? raw : raw.content;
    if (!text) throw new Error('模型未返回周目总结');
    return 解析总结(text);
  } finally {
    周目总结中.value = false;
  }
}

export function 封存当前周目(engine: 世界引擎, draft: 周目总结草稿, selected: readonly 轮回人物候选[]): 周目档案 {
  if (engine.周目.状态 === '已完成') throw new Error('本周目已经封存');
  const 人物志 = Object.fromEntries(
    selected.map(person => [
      person.名称,
      {
        名称: person.名称,
        类型: person.类型,
        继承方式: person.继承方式,
        人物志: 规范人物志(draft.人物志[person.名称] || person.摘要),
      },
    ]),
  );
  const entry = 周目档案Schema.parse({
    编号: engine.周目.编号,
    标题: draft.标题,
    内容: draft.内容,
    结局: draft.结局,
    完成时间: Date.now(),
    人物志,
    MVU继承快照: 构建MVU继承快照(人物志),
  });

  const saved = 保存周目档案(entry);
  engine.周目.状态 = '已完成';
  const variables = getVariables({ type: 'chat' });
  _.set(variables, '世界引擎', engine);
  replaceVariables(variables, { type: 'chat' });
  return saved;
}
