  font-size: 1.25rem;\n  letter-spacing: 0.28em;\n  color: var(--c-text);\n  text-shadow: 0 0 14px rgba(201, 160, 92, 0.25);\n  line-height: 1.2;\n}\n.we-title-sub {\n  font-size: 0.58rem;\n  letter-spacing: 0.2em;\n  color: var(--c-text-faint);\n  font-family: var(--font-ui);\n}\n\n.we-header-actions {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n}\n\n.we-btn-primary {\n  display: flex;\n  align-items: center;\n  gap: 7px;\n  padding: 8px 18px;\n  background: linear-gradient(145deg, rgba(212, 86, 80, 0.22), rgba(100, 24, 24, 0.4));\n  border: 1px solid var(--c-border-blood);\n  border-radius: var(--radius-sm);\n  color: var(--c-text);\n  font-family: var(--font-ui);\n  font-size: 0.92rem;\n  letter-spacing: 0.12em;\n  cursor: pointer;\n  transition: all 0.3s var(--ease-out-soft);\n  i {\n    font-size: 0.75rem;\n  }\n  &:hover:not(:disabled) {\n    box-shadow:\n      0 0 16px var(--c-accent-glow),\n      inset 0 0 12px rgba(212, 86, 80, 0.08);\n    border-color: var(--c-accent-bright);\n    background: linear-gradient(145deg, rgba(212, 86, 80, 0.35), rgba(130, 30, 30, 0.5));\n    transform: translateY(-1px);\n  }\n  &:disabled {\n    opacity: 0.45;\n    cursor: wait;\n  }\n}\n.we-btn-icon {\n  width: 34px;\n  height: 34px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  background: rgba(0, 0, 0, 0.35);\n  border: 1px solid var(--c-border);\n  border-radius: var(--radius-sm);\n  color: var(--c-text-dim);\n  cursor: pointer;\n  transition: all 0.3s var(--ease-out-soft);\n  &:hover {\n    color: var(--c-accent-bright);\n    border-color: var(--c-border-blood);\n    background: rgba(212, 86, 80, 0.08);\n  }\n}\n\n/* ═══ Tabs ═══ */\n.we-tabs {\n  display: flex;\n  gap: 0;\n  padding: 0 16px;\n  border-bottom: 1px solid var(--c-border-mid);\n  background: rgba(0, 0, 0, 0.25);\n  flex-shrink: 0;\n  overflow-x: auto;\n  position: relative;\n}\n.we-tabs::after {\n  content: '';\n  position: absolute;\n  bottom: -1px;\n  left: 0;\n  right: 0;\n  height: 1px;\n  background: linear-gradient(\n    90deg,\n    transparent 0%,\n    var(--c-border-strong) 30%,\n    var(--c-border-strong) 70%,\n    transparent 100%\n  );\n}\n\n.we-tab-btn {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  padding: 11px 18px;\n  background: transparent;\n  border: none;\n  border-bottom: 2px solid transparent;\n  color: var(--c-text-faint);\n  font-family: var(--font-ui);\n  font-size: 0.9rem;\n  letter-spacing: 0.12em;\n  cursor: pointer;\n  position: relative;\n  white-space: nowrap;\n  transition: color 0.3s var(--ease-out-soft);\n  margin-bottom: -1px;\n  i {\n    font-size: 0.92rem;\n    transition: transform 0.3s var(--ease-out-soft);\n  }\n  &:hover {\n    color: var(--c-text-dim);\n    i {\n      transform: translateY(-1px);\n    }\n  }\n  &.active {\n    color: var(--c-bronze-light);\n    border-bottom-color: var(--c-accent-bright);\n    i {\n      color: var(--c-accent-bright);\n    }\n    &::after {\n      content: '';\n      position: absolute;\n      bottom: -2px;\n      left: 25%;\n      right: 25%;\n      height: 2px;\n      background: linear-gradient(90deg, transparent, var(--c-accent-bright), transparent);\n      box-shadow: 0 0 10px var(--c-accent-glow);\n    }\n  }\n}\n\n/* ═══ Content ═══ */\n.we-content {\n  flex: 1;\n  overflow-y: auto;\n  padding: 20px;\n  min-height: 0;\n}\n\n/* ═══ 叙述弹层 ═══ */\n.we-narrative {\n  position: absolute;\n  inset: 0;\n  background: rgba(4, 5, 6, 0.82);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  z-index: 50;\n  padding: 28px;\n}\n.we-narrative-inner {\n  max-width: 520px;\n  padding: 26px;\n  background: linear-gradient(160deg, var(--c-panel-raised), var(--c-panel));\n  border: 1px solid var(--c-border-mid);\n  border-radius: var(--radius-md);\n  box-shadow:\n    0 4px 32px rgba(0, 0, 0, 0.5),\n    0 0 40px rgba(212, 86, 80, 0.12);\n  position: relative;\n}\n.we-narrative-label {\n  display: flex;\n  align-items: center;\n  gap: 7px;\n  font-size: 0.76rem;\n  color: var(--c-accent-bright);\n  letter-spacing: 0.18em;\n  font-family: var(--font-brush);\n}\n.we-narrative-inner p {\n  font-size: 0.86rem;\n  line-height: 1.85;\n  color: var(--c-text-dim);\n  letter-spacing: 0.03em;\n  margin: 0;\n}\n.we-narrative-hint {\n  display: block;\n  margin-top: 16px;\n  text-align: right;\n  font-size: 0.6rem;\n  color: var(--c-text-ghost);\n  letter-spacing: 0.1em;\n}\n\n.we-fade-enter-active,\n.we-fade-leave-active {\n  transition: opacity 0.25s;\n}\n.we-fade-enter-from,\n.we-fade-leave-to {\n  opacity: 0;\n}\n\n/* tab 切换顺滑过渡 */\n.we-tab-pane {\n  min-width: 0;\n}\n.we-tab-enter-active {\n  transition:\n    opacity 0.22s var(--ease-out-soft),\n    transform 0.22s var(--ease-out-soft);\n  will-change: transform, opacity;\n}\n.we-tab-leave-active {\n  transition:\n    opacity 0.14s var(--ease-out-soft),\n    transform 0.14s var(--ease-out-soft);\n  will-change: transform, opacity;\n}\n.we-tab-enter-from {\n  opacity: 0;\n  transform: translateY(8px);\n}\n.we-tab-leave-to {\n  opacity: 0;\n  transform: translateY(-6px);\n}\n\n@media (max-width: 599px) {\n  .we-narrative {\n    padding: 16px;\n  }\n  .we-narrative-inner {\n    max-height: calc(100% - 24px);\n    overflow-y: auto;\n    padding: 20px;\n  }\n  .we-tab-enter-from,\n  .we-tab-leave-to {\n    transform: none;\n  }\n}\n"],"sourceRoot":""}]);
