// 世界引擎 · 世界推进
// 调用 generateRaw（custom_api 独立模型，严禁注入 chat_history）让 LLM 读「世界状态 + 主线摘要」，
// 输出纯文本【叙述】+【变更指令】，脚本自解析指令 patch 世界状态。
// 纯文本协议兼容所有渠道（含不支持 json_schema 的国产模型/中转）。
import { 世界状态Schema } from './schema';
import { ref } from 'vue';
import { 生成世界氛围 } from './氛围';
import { 读取主线状态 } from './主线状态';
// 推进进行中状态：模块级共享 ref，跨弹窗开关存活。
// 手动按钮直接绑定此 ref，关闭弹窗后后台推进仍能反映到重开后的按钮状态。
export const 推进中 = ref(false);
export function 通知(msg, type = 'info') {
    try {
        const t = window.parent?.toastr ?? window.toastr;
        if (t && typeof t[type] === 'function')
            t[type](msg);
    }
    catch { /* 跨域或 toastr 不可用时静默 */ }
}
function 系统提示词() {
    return `你是黑暗奇幻修仙世界的「世界引擎」。目标：让世界持续产生有因果、有代价、有余波的变化，同时保持状态短、准、新。每轮必须先审计全部模块，再只写真正发生的变化；新状态覆盖旧状态，无用内容及时删除。

【不可违背的设定】
1. 五域仅中州、东荒、西漠、南岭、北冥；天京与东平/河朔/临江/云岫四州、天渊关均属中州。
2. 城镇/宗门仅维持局部秩序，荒野长期危险。正道七宗占高端战力，魔道四宗手段诡异，天渊停战脆弱；天道盟禁止大规模以凡人血祭、炼材。
3. 古神是彼此独立的秩序侧存在，从未被天渊封印，不靠污染扩张；奈亚是外神。旧日支配者才制造梦魇和认知污染；只有克苏鲁封于天渊，哈斯塔、伊格未被天渊封印。
4. 凡人/非修士能以行政、军队、商路、技艺、情报和互助改变世界。秘境逾时会石化；旧日污染和大型灾害不能被单一强者轻易根除。
5. 【角色卡当前状态】是时间、地点、身份、重要人物位置、古神和旧日状态的最高事实；冲突时以它为准。不得替主角行动、决定或制造未发生的遭遇。

【内部推进流程——只思考，不输出】
A. 判断从上次推进到当前经过的合理时间尺度；没有证据时只推进“近日”，不得自造纪元。
B. 选一条主因果链：压力/机会 → 行动者欲望与判断 → 具体行动 → 资源或风险代价 → 可观察结果；再允许 1~2 条由它引起的余波。精彩来自选择、误判、交换、牺牲和后果，不来自无因怪事或强行大战。
C. 逐项审计五模块，未变化则不写指令：
   - 势力：更新 1~3 个真正响应局势的态势/内部动向/实力影响；数值变化必须有事件依据。
   - 人物：优先更新 2~5 名相关人物。每人须有当前目标、具体做法、眼前阻碍或代价、位置和本轮实际结果；禁止“继续修炼/四处调查/处理事务”等空话。人物应主动选择、结盟、隐瞒、犯错、转向或付出代价，不能全都围着主角转。
   - 地区：更新 1~3 个承受结果的地区；当前事件必须是正在发生的新状态，旧事件结束后直接覆盖。近期传闻只留 0~3 条仍有用的新信息。
   - 暗流：更新 0~2 条。成熟度随明确条件升降；达到 80 才可逼近爆发。爆发时同轮 add 世界事件并 remove 原暗流；消弭或失去作用也 remove。
   - 世界事件：仅记录跨地区、改变格局或长期留痕的结果，普通动静只放地区/人物。失效且不再影响当下的动态事件可 remove；历史里程碑保留。
D. 清理生命周期：人物死亡/退隐/彻底失去叙事作用可 remove，但角色卡仍跟踪的人物不得删；旧传闻用整数组 set 替换；同义重复条目合并，不保留“已结束但还占位”的动态内容。

【高密度写入规则】
1. 通常输出 6~14 条、最多 18 条指令，覆盖至少 3 个模块；没有真实变化的模块不凑数。每条必须服务同一因果网。
2. 人物、地区、暗流优先用一次 set 替换完整对象，使字段同步且旧文字自然淘汰：
   人物字段=称号,势力,当前动向,所在地,状态,最近变化
   地区字段=区域,当前事件,氛围,安全度,近期传闻
   暗流字段=涉及势力,成熟度,描述,是否已爆发
3. 文本限长：当前动向≤72字，最近变化≤60字，地区事件≤72字，单条传闻≤48字，暗流描述≤88字，世界事件描述≤100字/影响≤72字。写事实，不复述固定设定。
4. 势力分类仅正道|魔道|皇朝|散修|妖族|中立|其他；地区区域仅中州|东荒|西漠|南岭|北冥。path 使用点号。
5. 输出叙述 120~220 字，概括因果与余波，不复读全部指令，不用“暗流涌动/诡异气息”代替可观察事实。

严格按以下格式输出，不要输出任何其他内容：

【叙述】
（120~220字）

【变更指令】
set | 人物动向.沈清辞 | {"称号":"太虚剑宗首席","势力":"太虚剑宗","当前动向":"护送受伤弟子撤离荒道，并追查错误路标来源","所在地":"中州·东平州","状态":"轻伤","最近变化":"放弃原定闭关，截获一枚伪造的联盟路引"}
set | 地区事件.东平州 | {"区域":"中州","当前事件":"三支商队因伪造路引滞留关驿","氛围":"戒备、拥堵","安全度":51,"近期传闻":["路引墨迹来自天京官坊","失踪向导曾替灵台司办事"]}
set | 暗流涌动.伪造路引网 | {"涉及势力":["灵台司","散修联盟"],"成熟度":46,"描述":"有人借官坊纸墨把商队引向废弃驿道，以失踪者测试沿线禁制","是否已爆发":false}
set | 势力.散修联盟.内部动向 | 暂停东平州三条荒道任务，派收尸人与识路客复核路标
add | 世界事件 | {"时间":"近日","事件":"东平路引案","描述":"伪造路引导致多支商队失踪，官坊纸墨流入黑市","影响":"东平关驿收紧，灵台司与散修联盟互查"}
remove | 暗流涌动.已经结算的旧暗线

指令说明：
- set：设置/完整替换；inc：数值增减；add：数组追加；remove：删除记录或数组下标。
- remove 数组多项时按下标从大到小；无变化不要输出解释或占位指令。`;
}
// 把 custom_api 配置转成 generateRaw 的参数（未配置则不传）
function 构建custom_api(api) {
    if (!api || !api.apiurl || !api.model)
        return {};
    return {
        custom_api: {
            source: api.source,
            apiurl: api.apiurl,
            key: api.key || undefined,
            model: api.model,
        },
    };
}
// 解析【叙述】段
function 解析叙述(text) {
    const m = text.match(/【叙述】([\s\S]*?)(?=【变更指令】|$)/);
    return m ? m[1].trim() : '';
}
// 尝试把字符串值转成 number / boolean / object，否则保留字符串
function 转换值(raw) {
    const s = raw.trim();
    if (s === '')
        return '';
    // JSON 对象/数组
    if (s.startsWith('{') || s.startsWith('[')) {
        try {
            return JSON.parse(s);
        }
        catch {
            return s;
        }
    }
    // 数字
    if (/^-?\d+(\.\d+)?$/.test(s))
        return Number(s);
    return s;
}
// 解析【变更指令】段为指令数组
export function 解析指令(text) {
    const block = text.match(/【变更指令】([\s\S]*?)$/);
    if (!block)
        return [];
    const 指令 = [];
    for (const line of block[1].split('\n')) {
        const trimmed = line.trim();
        if (!trimmed || !/^(set|inc|add|remove)\s*\|/i.test(trimmed))
            continue;
        const parts = trimmed.split('|').map(p => p.trim());
        const op = parts[0].toLowerCase();
        const path = parts[1] ?? '';
        if (!path)
            continue;
        const value = parts.length >= 3 ? 转换值(parts.slice(2).join('|')) : undefined;
        指令.push({ op, path, value });
    }
    // 防止模型失控输出大量细碎写入；高密度提示词约定最多 18 条。
    return 指令.slice(0, 18);
}
// 单条指令原地应用（不校验）。非法路径/类型抛错，由调用方回滚。
function 单条应用(状态, cmd) {
    const { op, path, value } = cmd;
    const pathParts = _.toPath(path);
    const 允许根 = new Set(['势力', '人物动向', '地区事件', '世界事件', '暗流涌动']);
    if (!pathParts.length || !允许根.has(pathParts[0]) || pathParts.some(part => ['__proto__', 'prototype', 'constructor'].includes(part))) {
        throw new Error(`禁止写入路径: ${path}`);
    }
    switch (op) {
        case 'set':
            _.set(状态, path, value);
            break;
        case 'inc': {
            const cur = _.get(状态, path, 0);
            _.set(状态, path, Number(cur) + Number(value));
            break;
        }
        case 'add': {
            const arr = _.get(状态, path);
            if (Array.isArray(arr)) {
                arr.push(value);
            }
            else if (arr === undefined) {
                _.set(状态, path, [value]);
            }
            else {
                throw new Error(`add 目标非数组: ${path}`);
            }
            break;
        }
        case 'remove': {
            // _.unset(array, index) 会留下空洞并使 schema 校验失败；数组项必须真正移除。
            const last = pathParts.at(-1) ?? '';
            const parentPath = pathParts.slice(0, -1);
            const parent = parentPath.length ? _.get(状态, parentPath) : 状态;
            if (Array.isArray(parent) && /^\d+$/.test(last)) {
                const index = Number(last);
                if (index < 0 || index >= parent.length)
                    throw new Error(`remove 数组下标越界: ${path}`);
                parent.splice(index, 1);
            }
            else {
                _.unset(状态, pathParts);
            }
            break;
        }
        default:
            throw new Error(`未知指令: ${op}`);
    }
}
// 把状态回滚到快照：清空自身键后深拷贝快照内容，保留原对象引用。
function 回滚(状态, 快照) {
    for (const k of Object.keys(状态))
        delete 状态[k];
    Object.assign(状态, 快照);
}
// 应用指令：逐条试应用 + schema 校验，非法指令回滚跳过，避免脏数据写回聊天变量导致面板黑屏。
export function 应用指令(状态, 指令) {
    let 成功 = 0;
    let 跳过 = 0;
    for (const cmd of 指令) {
        const 快照 = klona(状态);
        try {
            单条应用(状态, cmd);
        }
        catch (e) {
            回滚(状态, 快照);
            console.warn('[世界引擎] 指令执行失败，跳过', cmd, e);
            跳过++;
            continue;
        }
        const r = 世界状态Schema.safeParse(状态);
        if (!r.success) {
            回滚(状态, 快照);
            console.warn('[世界引擎] 指令产生非法状态，跳过', cmd, r.error);
            跳过++;
            continue;
        }
        // 写回 schema 的 transform/prefault 结果，使安全度、成熟度等数值实际被限幅在 0~100。
        回滚(状态, r.data);
        成功++;
    }
    return { 成功, 跳过 };
}
function 限长(value, maxLength) {
    const compact = value.trim().replace(/\s+/g, ' ');
    return compact.length > maxLength ? `${compact.slice(0, maxLength - 1)}…` : compact;
}
function 去重取末尾(values, maxCount, maxLength) {
    const seen = new Set();
    const result = [];
    for (let i = values.length - 1; i >= 0; i--) {
        const value = 限长(String(values[i] ?? ''), maxLength);
        if (!value || seen.has(value))
            continue;
        seen.add(value);
        result.push(value);
        if (result.length >= maxCount)
            break;
    }
    return result.reverse();
}
/**
 * 推进后的硬性瘦身：保留信息密度，限制模型偶发赘述和无限追加。
 * 固定势力/地区/人物不按数量裁剪，只约束动态文本和数组生命周期。
 */
export function 整理世界状态(状态) {
    const next = klona(状态);
    for (const faction of Object.values(next.势力)) {
        faction.态势 = 限长(faction.态势, 16);
        faction.内部动向 = 限长(faction.内部动向, 72);
        faction.与主角关系 = 限长(faction.与主角关系, 20);
        faction.描述 = 限长(faction.描述, 88);
    }
    for (const person of Object.values(next.人物动向)) {
        person.称号 = 限长(person.称号, 24);
        person.势力 = 限长(person.势力, 24);
        person.当前动向 = 限长(person.当前动向, 72);
        person.所在地 = 限长(person.所在地, 40);
        person.状态 = 限长(person.状态, 16);
        person.最近变化 = 限长(person.最近变化, 60);
    }
    for (const region of Object.values(next.地区事件)) {
        region.当前事件 = 限长(region.当前事件, 72);
        region.氛围 = 限长(region.氛围, 24);
        region.近期传闻 = 去重取末尾(region.近期传闻, 3, 48);
    }
    for (const undercurrent of Object.values(next.暗流涌动)) {
        undercurrent.涉及势力 = 去重取末尾(undercurrent.涉及势力, 4, 24);
        undercurrent.描述 = 限长(undercurrent.描述, 88);
    }
    const seenEvents = new Set();
    const events = [...next.世界事件].reverse().filter(event => {
        event.时间 = 限长(event.时间, 24);
        event.事件 = 限长(event.事件, 32);
        event.描述 = 限长(event.描述, 100);
        event.影响 = 限长(event.影响, 72);
        const key = `${event.时间}\u0000${event.事件}`;
        if (!event.事件 || seenEvents.has(key))
            return false;
        seenEvents.add(key);
        return true;
    }).reverse();
    const 历史里程碑 = events.filter(event => /上古|中古|远古|二百年前/.test(event.时间)).slice(0, 5);
    const 动态事件 = events.filter(event => !历史里程碑.includes(event)).slice(-12);
    next.世界事件 = [...历史里程碑, ...动态事件];
    return 世界状态Schema.parse(next);
}
// 推进世界：手动按钮 / 自动触发共用入口。返回叙述文本供 UI 展示。
// auto=true 表示自动推进触发（无弹窗可用），会用 toastr 把叙述一并提示给用户。
export async function 推进世界(auto = false) {
    if (推进中.value) {
        通知('世界正在推进中，请稍候', 'warning');
        return null;
    }
    推进中.value = true;
    通知(auto ? '世界引擎自动推演中…' : '世界引擎推演中…', 'info');
    try {
        const variables = getVariables({ type: 'chat' });
        const engine = (variables.世界引擎 ?? {});
        const 状态 = engine.世界状态 ?? {};
        const 摘要 = engine.摘要?.近期摘要 ?? '（暂无主线摘要）';
        const api = engine.配置?.custom_api ?? null;
        const 主线状态 = 读取主线状态();
        const rawResult = await generateRaw({
            should_silence: true,
            ...构建custom_api(api),
            ordered_prompts: [
                { role: 'system', content: 系统提示词() },
                // 紧凑 JSON 能显著减少每次推进输入 token；字段名本身已足够表达结构。
                { role: 'system', content: `【当前世界状态】${JSON.stringify(状态)}` },
                { role: 'system', content: `【角色卡当前状态】${JSON.stringify(主线状态 ?? null)}` },
                { role: 'system', content: `【主线剧情摘要】\n${摘要}` },
                { role: 'user', content: '推进一次：全局审计、局部结算、更新新内容并删除旧无用内容。严格按格式输出。' },
            ],
        });
        const result = typeof rawResult === 'string' ? rawResult : rawResult.content;
        if (!result)
            throw new Error('LLM 未返回文本内容');
        const 叙述 = 解析叙述(result);
        const 指令 = 解析指令(result);
        const 指令状态 = klona(状态);
        const { 成功, 跳过 } = 应用指令(指令状态, 指令);
        const 新状态 = 整理世界状态(指令状态);
        engine.世界状态 = 新状态;
        engine.世界氛围 = 生成世界氛围(新状态);
        engine.上次推进楼层 = getLastMessageId();
        _.set(variables, '世界引擎', engine);
        replaceVariables(variables, { type: 'chat' });
        console.info(`[世界引擎] 推进完成：${成功} 条指令生效，${跳过} 条跳过`);
        if (auto) {
            // 自动推进无弹窗，把叙述作为系统提示直接展示给用户
            通知(叙述 ? `世界已自动推演演进：\n${叙述}` : '世界已自动推演演进', 'success');
        }
        else {
            通知('世界已推演演进', 'success');
        }
        return { 叙述, 成功, 跳过 };
    }
    catch (e) {
        console.error('[世界引擎] 推进失败', e);
        通知('世界推演失败，世界状态未变更', 'error');
        return null;
    }
    finally {
        推进中.value = false;
    }
}
