// 世界引擎 · 跨聊天浏览器配置缓存
// 只缓存「配置」，不缓存世界状态、摘要或推进进度；新聊天首次初始化时作为默认值读取。

import { 世界引擎Schema, type 世界引擎 } from './schema';

export type 世界引擎配置 = 世界引擎['配置'];

interface 缓存存储 {
  getItem(key: string): string | null;
  setItem(key: string, value: string): void;
  removeItem(key: string): void;
}

export const 配置缓存键 = 'black-monk.world-engine.settings.v1';

function 取浏览器存储(): 缓存存储 | null {
  try {
    if (typeof window === 'undefined') return null;
    return window.parent?.localStorage ?? window.localStorage;
  } catch {
    try {
      return window.localStorage;
    } catch {
      return null;
    }
  }
}

/** 读取并通过当前 Schema 规范缓存；无缓存、损坏或浏览器禁用存储时返回 null。 */
export function 读取缓存配置(storage: 缓存存储 | null = 取浏览器存储()): 世界引擎配置 | null {
  if (!storage) return null;
  try {
    const raw = storage.getItem(配置缓存键);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    return 世界引擎Schema.parse({ 配置: parsed }).配置;
  } catch (error) {
    console.warn('[世界引擎] 浏览器配置缓存损坏，已忽略', error);
    try { storage.removeItem(配置缓存键); } catch { /* 存储不可写时静默 */ }
    return null;
  }
}

/** 保存完整配置快照。返回 false 表示浏览器拒绝 localStorage，但聊天内配置仍可正常使用。 */
export function 保存缓存配置(
  config: 世界引擎配置,
  storage: 缓存存储 | null = 取浏览器存储(),
): boolean {
  if (!storage) return false;
  try {
    const normalized = 世界引擎Schema.parse({ 配置: config }).配置;
    storage.setItem(配置缓存键, JSON.stringify(normalized));
    return true;
  } catch (error) {
    console.warn('[世界引擎] 浏览器配置缓存写入失败', error);
    return false;
  }
}
