// 世界引擎 · 世界书触发宏
// 为暗流/势力/地区/人物注册宏。暗流只选当前最相关的一条，避免把整份世界状态塞进主线 prompt。
// 用法：{{暗流}} {{势力:太虚剑宗}} {{地区:天京城}} {{人物:沈清辞}}
// 命中即从聊天变量读对应条目，格式化成紧凑文本；查无则返回空串（条目不产生内容）。
import type { 世界状态 } from './schema';
import { 生成世界氛围 } from './氛围';
import { 读取主线状态, type 主线状态切片 } from './主线状态';
import { 格式化轮回记忆, 读取角色轮回档案 } from './轮回';

function 取状态(): 世界状态 | null {
  try {
    const variables = getVariables({ type: 'chat' });
    return _.get(variables, '世界引擎.世界状态') ?? null;
  } catch {
    return null;
  }
}

const 势力宏正则 = /\{\{势力:([^}]+)\}\}/g;
const 地区宏正则 = /\{\{地区:([^}]+)\}\}/g;
const 人物宏正则 = /\{\{人物:([^}]+)\}\}/g;
const 氛围宏正则 = /\{\{世界氛围\}\}/g;
const 暗流宏正则 = /\{\{暗流\}\}/g;
const 轮回记忆宏正则 = /\{\{轮回记忆\}\}/g;

const 五域泛称 = new Set(['中州', '东荒', '西漠', '南岭', '北冥', '五域']);

function 地点关键词(place: string): string[] {
  return place
    .split(/[·・／/、，,\s]+/)
    .map(value => value.trim())
    .filter(value => value.length >= 2 && !五域泛称.has(value) && !['未知之地', '未知'].includes(value));
}

function 压缩暗流描述(text: string, maxLength = 40): string {
  const compact = text.replace(/\s+/g, '').replace(/[。；;]+$/g, '');
  return compact.length > maxLength ? `${compact.slice(0, maxLength)}…` : compact;
}

/** 只输出一条、定长、与当前正文最相关的幕后暗流。 */
export function 生成暗流正文切片(状态: 世界状态 | null, 主线: 主线状态切片 | null): string {
  if (!状态) return '';

  const 当前地点 = 主线?.世界.当前地点 ?? '';
  const 关键词 = 地点关键词(当前地点);
  const 主角宗门 = 主线?.主角.宗门 ?? '';
  const 同地人物势力 = new Set(
    Object.values(主线?.重要人物 ?? {})
      .filter(person => 关键词.some(keyword => person.所在地.includes(keyword)))
      .map(person => person.势力)
      .filter(Boolean),
  );

  const candidates = Object.entries(状态.暗流涌动 ?? {})
    .filter(([, undercurrent]) => !undercurrent.是否已爆发 && undercurrent.成熟度 > 0)
    .map(([name, undercurrent]) => {
      const searchText = `${name}${undercurrent.描述}${undercurrent.涉及势力.join('')}`;
      let score = undercurrent.成熟度;
      if (关键词.some(keyword => searchText.includes(keyword))) score += 35;
      if (主角宗门 && 主角宗门 !== '无' && undercurrent.涉及势力.includes(主角宗门)) score += 20;
      if (undercurrent.涉及势力.some(faction => 同地人物势力.has(faction))) score += 15;
      if (undercurrent.成熟度 >= 80) score += 30;
      return { name, undercurrent, score };
    })
    .sort((a, b) => b.score - a.score || b.undercurrent.成熟度 - a.undercurrent.成熟度);

  const selected = candidates[0];
  if (!selected) return '';

  const { name, undercurrent } = selected;
  const 阶段 = undercurrent.成熟度 >= 80 ? '临界' : undercurrent.成熟度 >= 50 ? '酝酿' : '潜伏';
  const 表现约束 = undercurrent.成熟度 >= 80
    ? '可近爆发，须有因果'
    : undercurrent.成熟度 >= 50
      ? '相关时显一项征兆'
      : '相关时仅留一处伏笔';
  const 涉及 = undercurrent.涉及势力.slice(0, 2).join('/');
  const 描述 = 压缩暗流描述(undercurrent.描述);

  return `【暗流·勿明示】${name}|${阶段}${undercurrent.成熟度}${涉及 ? `|${涉及}` : ''}${描述 ? `：${描述}` : ''}；${表现约束}`;
}

function 格式化地区(名: string, region: 世界状态['地区事件'][string]): string {
  const 传闻 = region.近期传闻?.length ? ` | 传闻:${region.近期传闻.join('；')}` : '';
  return `【地区·${名}】区域:${region.区域 ?? '中州'} | 安全度:${region.安全度 ?? 50} | 氛围:${region.氛围 ?? '未知'}${region.当前事件 ? ` | 当前事件:${region.当前事件}` : ''}${传闻}`;
}

function 匹配当前地区(状态: 世界状态, 地点: string): [string, 世界状态['地区事件'][string]] | null {
  if (!地点 || 地点 === '未知之地') return null;
  const entries = Object.entries(状态.地区事件 ?? {}).sort(([a], [b]) => b.length - a.length);
  const exact = entries.find(([name]) => 地点.includes(name));
  if (exact) return exact;
  const domain = ['中州', '东荒', '西漠', '南岭', '北冥'].find(name => 地点.includes(name));
  return domain ? (entries.find(([name]) => name === domain) ?? null) : null;
}

export function 注册世界书宏(): { unregister: () => void } {
  const r0 = registerMacroLike(氛围宏正则, () => {
    try {
      const 主线 = 读取主线状态();
      const 状态 = 取状态();
      const 氛围 = 生成世界氛围(状态);
      if (!主线 || !状态) return 氛围;
      const 当前地区 = 匹配当前地区(状态, 主线.世界.当前地点);
      const 定位 = `【当前时空】${主线.世界.当前年号}·${主线.世界.当前时间} | ${主线.世界.当前地点}`;
      return [氛围, 定位, 当前地区 ? 格式化地区(...当前地区) : ''].filter(Boolean).join('\n');
    } catch {
      return '城镇灯火尚存，荒野危机未息。';
    }
  });

  const r4 = registerMacroLike(暗流宏正则, () => 生成暗流正文切片(取状态(), 读取主线状态()));

  const r5 = registerMacroLike(轮回记忆宏正则, () => {
    try {
      const loop = _.get(getVariables({ type: 'chat' }), '世界引擎.周目');
      const source = Number(loop?.来源周目 ?? 0);
      if (!loop?.继承已应用 || source <= 0) return '';
      const entry = 读取角色轮回档案().档案[String(source)];
      return entry ? 格式化轮回记忆(entry) : '';
    } catch (error) {
      console.warn('[世界引擎] 轮回记忆宏读取失败', error);
      return '';
    }
  });

  const r1 = registerMacroLike(势力宏正则, (_ctx, _sub, 名: string) => {
    const f = 取状态()?.势力?.[名?.trim()];
    if (!f) return '';
    return `【势力·${名}】分类:${f.分类 ?? '其他'} | 态势:${f.态势 ?? '平稳'} | 影响:${f.影响范围 ?? 0} | 实力:${f.实力 ?? 0} | 与主角关系:${f.与主角关系 ?? '中立'}${f.内部动向 ? ` | 内部动向:${f.内部动向}` : ''}${f.描述 ? ` | 简介:${f.描述}` : ''}`;
  });

  const r2 = registerMacroLike(地区宏正则, (_ctx, _sub, 名: string) => {
    const r = 取状态()?.地区事件?.[名?.trim()];
    if (!r) return '';
    return 格式化地区(名, r);
  });

  const r3 = registerMacroLike(人物宏正则, (_ctx, _sub, 名: string) => {
    const p = 取状态()?.人物动向?.[名?.trim()];
    if (!p) return '';
    return `【人物·${名}】${p.称号 ? `称号:${p.称号} | ` : ''}${p.势力 ? `势力:${p.势力} | ` : ''}状态:${p.状态 ?? '正常'}${p.所在地 ? ` | 所在地:${p.所在地}` : ''}${p.当前动向 ? ` | 当前动向:${p.当前动向}` : ''}${p.最近变化 ? ` | 最近变化:${p.最近变化}` : ''}`;
  });

  return {
    unregister: () => { r0.unregister(); r1.unregister(); r2.unregister(); r3.unregister(); r4.unregister(); r5.unregister(); },
  };
}
