// 世界引擎 · 世界状态 schema 与种子数据
// 世界状态存于聊天变量 {type:'chat'} 的「世界引擎」键下，全聊天单一真相，不围绕主角。
const 区域枚举 = z.enum(['中州', '西漠', '东荒', '南岭', '北冥']);
const 势力分类枚举 = z.enum(['正道', '魔道', '皇朝', '散修', '妖族', '中立', '其他']);
/** 设定与种子版本：用于对旧聊天中的世界引擎数据做非破坏性迁移。 */
export const 当前设定版本 = 3;
export const 主线摘要字数上限 = 200;
export const 周目经历字数上限 = 100;
/**
 * 摘要永久硬上限：先清理模型常见包装；超限时保留末尾最新内容，并尽量从句界开始。
 * 返回值按 JS 字符长度严格不超过 200。
 */
export function 规范主线摘要(value) {
    const compact = String(value ?? '')
        .replace(/^```(?:text|markdown)?\s*/i, '')
        .replace(/```\s*$/i, '')
        .replace(/^\s*(?:【主线(?:剧情)?摘要】|主线(?:剧情)?摘要[:：])\s*/i, '')
        .replace(/\s+/g, ' ')
        .trim();
    if (compact.length <= 主线摘要字数上限)
        return compact;
    let latest = compact.slice(-(主线摘要字数上限 - 1));
    const boundary = latest.slice(0, 80).search(/[。！？；]/);
    if (boundary >= 0)
        latest = latest.slice(boundary + 1).trimStart();
    return `…${latest}`.slice(0, 主线摘要字数上限);
}
/** 单条周目经历硬上限：保留本次阶段最重要的结果，供结局总结串联全周目。 */
export function 规范周目经历(value) {
    const compact = String(value ?? '')
        .replace(/^```(?:text|markdown)?\s*/i, '')
        .replace(/```\s*$/i, '')
        .replace(/^\s*(?:【?(?:本周目)?经历】?[:：])\s*/i, '')
        .replace(/\s+/g, ' ')
        .trim();
    return compact.slice(0, 周目经历字数上限);
}
// 数值字段统一用 preprocess 兜底空值，再 transform 限幅
const 数值 = (min, max, 默认) => z
    .preprocess(v => (v === null || v === undefined ? 默认 : Number(v)), z.number())
    .transform(v => _.clamp(v, min, max))
    .prefault(默认);
export const 世界状态Schema = z
    .object({
    势力: z
        .record(z.string().describe('势力名'), z
        .object({
        分类: 势力分类枚举.prefault('其他'),
        影响范围: 数值(0, 100, 30),
        实力: 数值(0, 100, 30),
        态势: z.string().prefault('平稳'),
        内部动向: z.string().prefault(''),
        与主角关系: z.string().prefault('中立'),
        描述: z.string().prefault(''),
    })
        .prefault({}))
        .prefault({}),
    人物动向: z
        .record(z.string().describe('人物名'), z
        .object({
        称号: z.string().prefault(''),
        势力: z.string().prefault(''),
        当前动向: z.string().prefault(''),
        所在地: z.string().prefault(''),
        状态: z.string().prefault('正常'),
        最近变化: z.string().prefault(''),
    })
        .prefault({}))
        .prefault({}),
    地区事件: z
        .record(z.string().describe('地区名'), z
        .object({
        区域: 区域枚举.prefault('中州'),
        当前事件: z.string().prefault(''),
        氛围: z.string().prefault(''),
        安全度: 数值(0, 100, 50),
        近期传闻: z.array(z.string()).prefault([]),
    })
        .prefault({}))
        .prefault({}),
    世界事件: z
        .array(z
        .object({
        时间: z.string().prefault(''),
        事件: z.string().prefault(''),
        描述: z.string().prefault(''),
        影响: z.string().prefault(''),
    })
        .prefault({}))
        .prefault([]),
    暗流涌动: z
        .record(z.string().describe('暗线名'), z
        .object({
        涉及势力: z.array(z.string()).prefault([]),
        成熟度: 数值(0, 100, 0),
        描述: z.string().prefault(''),
        是否已爆发: z.boolean().prefault(false),
    })
        .prefault({}))
        .prefault({}),
})
    .prefault({});
// 独立 API 配置：与主线模型隔离
const 源枚举 = z.enum(['openai', 'claude', 'deepseek']);
export const CustomApiSchema = z
    .object({
    source: 源枚举.prefault('openai'),
    apiurl: z.string().prefault(''),
    key: z.string().prefault(''),
    model: z.string().prefault(''),
})
    .prefault({});
export const 世界引擎Schema = z
    .object({
    设定版本: z.coerce.number().prefault(0),
    世界状态: 世界状态Schema.prefault({}),
    摘要: z
        .object({
        近期摘要: z.string().transform(规范主线摘要).prefault(''),
        上次摘要楼层: z.coerce.number().prefault(0),
    })
        .prefault({}),
    周目: z
        .object({
        编号: z.coerce.number().transform(value => Math.max(1, Math.trunc(value))).prefault(1),
        来源周目: z.coerce.number().transform(value => Math.max(0, Math.trunc(value))).prefault(0),
        状态: z.enum(['进行中', '已完成']).prefault('进行中'),
        继承已应用: z.boolean().prefault(false),
        经历: z
            .record(z.string().describe('经历序号'), z
            .object({
            起始楼层: z.coerce.number().prefault(0),
            结束楼层: z.coerce.number().prefault(0),
            内容: z.string().transform(规范周目经历).prefault(''),
        })
            .prefault({}))
            .prefault({}),
        上次经历楼层: z.coerce.number().prefault(0),
    })
        .prefault({}),
    上次推进楼层: z.coerce.number().prefault(0),
    // 一句话世界氛围：纯函数派生，供世界书常驻条目注入主线 prompt
    世界氛围: z.string().prefault(''),
    配置: z
        .object({
        // 自动摘要与自动推进完全独立；默认保持摘要更新，世界是否推进由用户另行决定。
        自动摘要: z.boolean().prefault(true),
        自动推进: z.boolean().prefault(false),
        自动推进间隔: z.coerce.number().prefault(10),
        摘要间隔: z.coerce.number().prefault(5),
        custom_api: CustomApiSchema.nullable().prefault(null),
    })
        .prefault({}),
})
    .prefault({});
