// 世界引擎 · 当前角色卡状态切片
// 世界引擎的独立世界状态存于 chat 变量；主角、时间、地点与超凡存在则以最新楼层的 stat_data 为权威来源。

export interface 主线状态切片 {
  游戏模式: '剧情模式' | '沙盒模式';
  世界: {
    当前年号: string;
    当前时间: string;
    当前地点: string;
  };
  主角: {
    名称: string;
    种族: string;
    称号: string;
    境界: string;
    宗门: string;
    修炼流派: string;
    本源: string;
    状态: string;
    san值: number;
  };
  重要人物: Record<string, { 势力: string; 关系: string; 所在地: string; 攻略: boolean }>;
  古神态势: Record<string, { 状态: string; 收服: boolean; 沉沦值: number }>;
  旧日态势: Record<string, { 状态: string; 位置: string; 封印状态: string; 污染强度: number; 已遭遇: boolean }>;
  当前秘境: { 名称: string; 品阶: string; 当前场景: string; 剩余刻数: number } | null;
}

export interface 羁绊人物候选 {
  名称: string;
  称号: string;
  境界: string;
  势力: string;
  关系: string;
  描述: string;
  所在地: string;
  当前在场: boolean;
}

function 字符串(value: unknown, fallback = ''): string {
  return typeof value === 'string' ? value : fallback;
}

function 数字(value: unknown, fallback = 0): number {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

/**
 * 读取状态栏的长期羁绊，必要时用同名“重要人物”和“在场”记录补全称号、所在地。
 * 返回独立快照，调用方不会反向修改 MVU 数据。
 */
export function 读取羁绊人物候选(): 羁绊人物候选[] {
  try {
    const variables = getVariables({ type: 'message', message_id: -1 });
    const stat = _.get(variables, 'stat_data');
    if (!stat || typeof stat !== 'object') return [];

    const 羁绊 = _.get(stat, '羁绊', {}) as Record<string, any>;
    const 重要人物 = _.get(stat, '重要人物', {}) as Record<string, any>;
    const 在场 = _.get(stat, '在场', {}) as Record<string, any>;
    const 当前地点 = 字符串(_.get(stat, '世界.当前地点'), '未知');
    const 保留键 = new Set(['__proto__', 'prototype', 'constructor']);

    return Object.entries(羁绊)
      .filter(([name, value]) => name.trim() && !保留键.has(name) && value && typeof value === 'object')
      .map(([name, value]) => {
        const important = 重要人物[name] ?? {};
        const 当前在场 = Object.prototype.hasOwnProperty.call(在场, name);
        const 重要人物地点 = 字符串(important.所在地, '');
        return {
          名称: name,
          称号: 字符串(important.称号),
          境界: 字符串(value.境界, 字符串(important.境界, '未知')),
          势力: 字符串(value.势力, 字符串(important.势力, '散修')),
          关系: 字符串(value.关系, 字符串(important.关系, '陌路人')),
          描述: 字符串(value.描述, 字符串(important.描述)),
          所在地: 当前在场 ? 当前地点 : 重要人物地点 && 重要人物地点 !== '未知' ? 重要人物地点 : '未知',
          当前在场,
        };
      });
  } catch (error) {
    console.warn('[世界引擎] 读取状态栏羁绊失败', error);
    return [];
  }
}

/** 读取最新楼层的 MVU stat_data；不依赖 Mvu 全局的初始化时序。 */
export function 读取主线状态(): 主线状态切片 | null {
  try {
    const variables = getVariables({ type: 'message', message_id: -1 });
    const stat = _.get(variables, 'stat_data');
    if (!stat || typeof stat !== 'object') return null;

    const 重要人物 = _.mapValues(_.get(stat, '重要人物', {}), value => ({
      势力: 字符串(value?.势力, '未知'),
      关系: 字符串(value?.关系, '中立'),
      所在地: 字符串(value?.所在地, '未知'),
      攻略: Boolean(value?.攻略),
    }));
    const 古神态势 = _.mapValues(_.get(stat, '古神列表', {}), value => ({
      状态: 字符串(value?.状态, '未知'),
      收服: Boolean(value?.收服),
      沉沦值: _.clamp(数字(value?.沉沦值), 0, 100),
    }));
    const 旧日态势 = _.mapValues(_.get(stat, '旧日支配者列表', {}), value => ({
      状态: 字符串(value?.状态, '未知'),
      位置: 字符串(value?.位置, '未知'),
      封印状态: 字符串(value?.封印状态, '未知'),
      污染强度: _.clamp(数字(value?.污染强度), 0, 100),
      已遭遇: Boolean(value?.已遭遇),
    }));
    const 秘境 = _.get(stat, '当前秘境');

    return {
      游戏模式: _.get(stat, '$flag.游戏模式') === '沙盒模式' ? '沙盒模式' : '剧情模式',
      世界: {
        当前年号: 字符串(_.get(stat, '世界.当前年号'), '太初'),
        当前时间: 字符串(_.get(stat, '世界.当前时间'), '未知'),
        当前地点: 字符串(_.get(stat, '世界.当前地点'), '未知之地'),
      },
      主角: {
        名称: 字符串(_.get(stat, '主角.名称'), '主角'),
        种族: 字符串(_.get(stat, '主角.种族'), '人族'),
        称号: 字符串(_.get(stat, '主角.称号'), ''),
        境界: 字符串(_.get(stat, '主角.境界'), '凡人'),
        宗门: 字符串(_.get(stat, '主角.宗门'), '无'),
        修炼流派: 字符串(_.get(stat, '主角.修炼流派'), '无'),
        本源: 字符串(_.get(stat, '主角.本源'), '未知'),
        状态: 字符串(_.get(stat, '主角.状态'), '正常'),
        san值: _.clamp(数字(_.get(stat, '主角.san值'), 80), 0, 100),
      },
      重要人物,
      古神态势,
      旧日态势,
      当前秘境: 秘境?.在秘境中
        ? {
            名称: 字符串(秘境.名称, '未知秘境'),
            品阶: 字符串(秘境.品阶, '未知'),
            当前场景: 字符串(秘境.当前场景, ''),
            剩余刻数: 数字(秘境.剩余刻数),
          }
        : null,
    };
  } catch (error) {
    console.warn('[世界引擎] 读取主线 stat_data 失败，本轮仅使用独立世界状态', error);
    return null;
  }
}

export function 格式化主线状态(state: 主线状态切片 | null): string {
  return state ? JSON.stringify(state, null, 2) : '（未读取到角色卡 stat_data）';
}
