// 世界引擎 · pinia store
// 封装聊天变量 {type:'chat'} 下「世界引擎」键的读写。
// 全聊天单一真相：读取时用 schema 解析兜底，写入时 klona 去 proxy。
import { defineStore } from 'pinia';
import { ref } from 'vue';
import { 当前设定版本, 世界引擎Schema, 种子世界状态 } from './schema';
import { 生成世界氛围 } from './氛围';
import { 通知 } from './推进';
import { 保存缓存配置, 读取缓存配置 } from './配置缓存';
const 变量键 = '世界引擎';
function 创建默认世界引擎() {
    const cached = 读取缓存配置();
    return 世界引擎Schema.parse({
        设定版本: 当前设定版本,
        世界状态: 种子世界状态,
        ...(cached ? { 配置: cached } : {}),
    });
}
const 旧人物动向 = {
    沈清辞: '闭关苦修太虚斩念诀最后一层',
    姜无忧: '在云岫州药王谷整理医脉通感心得',
    顾千卷: '深挖古神档案室残卷',
    柳不移: '坐镇中州总盟处理庶务',
    萧太薇: '批阅奏章周旋灵台司',
};
/**
 * 旧聊天非破坏性迁移：保留已推演的动态数值和新条目，
 * 只更正固定设定、旧种子原文及补入当前世界书已明确的基础条目。
 */
export function 迁移世界引擎(raw) {
    if (!raw || typeof raw !== 'object')
        return { data: raw, migrated: false };
    const data = klona(raw);
    const version = Number(data.设定版本 ?? 0);
    if (version >= 当前设定版本)
        return { data, migrated: false };
    const state = (_.isObject(data.世界状态) ? data.世界状态 : {});
    data.世界状态 = state;
    if (!_.isObject(data.周目))
        data.周目 = {};
    for (const key of ['势力', '人物动向', '地区事件', '暗流涌动']) {
        if (!_.isObject(state[key]))
            state[key] = {};
    }
    if (!Array.isArray(state.世界事件))
        state.世界事件 = [];
    // 古神是独立的秩序侧存在，不是单一政治阵营。
    delete state.势力.古神势力;
    const 有效分类 = new Set(['正道', '魔道', '皇朝', '散修', '妖族', '中立', '其他']);
    for (const faction of Object.values(state.势力)) {
        if (faction && !有效分类.has(faction.分类))
            faction.分类 = '其他';
    }
    for (const [name, seed] of Object.entries(种子世界状态.势力)) {
        const current = state.势力[name];
        if (!current) {
            state.势力[name] = klona(seed);
            continue;
        }
        // 分类与组织定位属于固定设定；数值、态势、动向与主角关系保留聊天演化结果。
        current.分类 = seed.分类;
        current.描述 = seed.描述;
    }
    for (const [name, seed] of Object.entries(种子世界状态.人物动向)) {
        const current = state.人物动向[name];
        if (!current || current.当前动向 === 旧人物动向[name]) {
            state.人物动向[name] = klona(seed);
        }
    }
    for (const [name, seed] of Object.entries(种子世界状态.地区事件)) {
        if (!state.地区事件[name])
            state.地区事件[name] = klona(seed);
    }
    // 移除旧引擎自行发明、当前世界书无依据的剑冢封印暗线。
    delete state.暗流涌动['剑冢封印松动'];
    for (const [name, seed] of Object.entries(种子世界状态.暗流涌动)) {
        if (!state.暗流涌动[name])
            state.暗流涌动[name] = klona(seed);
    }
    const eventNames = new Set(state.世界事件.map((event) => event?.事件));
    for (const event of 种子世界状态.世界事件) {
        if (!eventNames.has(event.事件))
            state.世界事件.push(klona(event));
    }
    data.设定版本 = 当前设定版本;
    return { data, migrated: true };
}
// 读取聊天变量里的世界引擎数据；不存在则用种子初始化并写回。
// 数据损坏（schema 校验失败）时回退种子并落盘，避免弹窗每次挂载都抛错导致黑屏无法恢复。
function 读取世界引擎() {
    const variables = getVariables({ type: 'chat' });
    const raw = _.get(variables, 变量键);
    let engine;
    if (!raw) {
        engine = 创建默认世界引擎();
        _.set(variables, 变量键, klona(engine));
        replaceVariables(variables, { type: 'chat' });
        console.info('[世界引擎] 首次初始化，写入种子数据');
    }
    else {
        const migration = 迁移世界引擎(raw);
        const r = 世界引擎Schema.safeParse(migration.data);
        if (r.success) {
            engine = r.data;
            const 摘要已规范 = _.get(migration.data, '摘要.近期摘要', '') !== engine.摘要.近期摘要;
            const 自动摘要已补全 = _.get(migration.data, '配置.自动摘要') === undefined;
            const 周目已补全 = _.get(migration.data, '周目') === undefined;
            if (migration.migrated || 摘要已规范 || 自动摘要已补全 || 周目已补全) {
                _.set(variables, 变量键, klona(engine));
                replaceVariables(variables, { type: 'chat' });
                if (migration.migrated)
                    console.info(`[世界引擎] 旧聊天数据已迁移至设定 v${当前设定版本}`);
                if (摘要已规范)
                    console.info('[世界引擎] 旧主线摘要已压缩至 200 字以内');
                if (自动摘要已补全)
                    console.info('[世界引擎] 旧聊天已补入独立的自动摘要开关（默认开启）');
                if (周目已补全)
                    console.info('[世界引擎] 当前聊天已初始化第一周目进度');
            }
        }
        else {
            console.error('[世界引擎] 聊天变量数据损坏，回退种子世界状态', r.error);
            通知('世界引擎数据损坏，已回退为初始世界状态', 'warning');
            engine = 创建默认世界引擎();
            _.set(variables, 变量键, klona(engine));
            replaceVariables(variables, { type: 'chat' });
        }
    }
    // 旧数据或刚播种时 世界氛围 为空，按当前状态派生（下次 persist 落盘）
    if (!engine.世界氛围)
        engine.世界氛围 = 生成世界氛围(engine.世界状态);
    return engine;
}
export const useWorldEngineStore = defineStore('world-engine', () => {
    const data = ref(读取世界引擎());
    // 首次升级且尚无缓存时，以当前聊天已有配置建立浏览器默认值；之后切换聊天不会自动覆盖。
    if (!读取缓存配置())
        保存缓存配置(data.value.配置);
    // 写回聊天变量（去 proxy）
    function persist() {
        const variables = getVariables({ type: 'chat' });
        _.set(variables, 变量键, klona(data.value));
        replaceVariables(variables, { type: 'chat' });
    }
    // 设置页专用：聊天内落盘的同时更新跨聊天浏览器默认配置。
    function persistConfig() {
        persist();
        if (!保存缓存配置(data.value.配置)) {
            通知('设置已保存到当前聊天，但浏览器缓存写入失败', 'warning');
        }
    }
    // 重新从聊天变量拉取最新（推进/摘要后或外部变更时调用）
    function refresh() {
        data.value = 读取世界引擎();
    }
    // 直接更新整体数据并持久化
    function commit(next) {
        data.value = next;
        persist();
    }
    return { data, persist, persistConfig, refresh, commit };
});
