c-border-mid);\n  }\n}\n.panel {\n  padding: 17px 19px;\n}\n.section-head {\n  display: flex;\n  align-items: flex-start;\n  justify-content: space-between;\n  gap: 18px;\n  padding-bottom: 11px;\n  border-bottom: 1px solid var(--c-hairline);\n  h3 {\n    margin: 0 0 4px;\n    color: var(--c-text);\n    font-family: var(--font-ui);\n    letter-spacing: 0.1em;\n    font-size: 1rem;\n  }\n  h3 i {\n    color: var(--c-bronze-light);\n    margin-right: 7px;\n  }\n  p {\n    margin: 0;\n    color: var(--c-text-faint);\n    font-size: 0.7rem;\n    line-height: 1.5;\n  }\n  > span {\n    color: var(--c-text-faint);\n    font-size: 0.7rem;\n    white-space: nowrap;\n  }\n}\n.timeline {\n  padding: 14px 0 0 7px;\n}\n.timeline-item {\n  display: grid;\n  grid-template-columns: 13px 1fr;\n  gap: 10px;\n  position: relative;\n  padding-bottom: 13px;\n  &::before {\n    content: '';\n    position: absolute;\n    left: 5px;\n    top: 10px;\n    bottom: -2px;\n    width: 1px;\n    background: var(--c-border-mid);\n  }\n  &:last-child::before {\n    display: none;\n  }\n  small {\n    color: var(--c-accent-bright);\n    font-size: 0.62rem;\n  }\n  p {\n    margin: 4px 0 0;\n    color: var(--c-text-dim);\n    font-size: 0.82rem;\n    line-height: 1.65;\n  }\n}\n.timeline-dot {\n  width: 11px;\n  height: 11px;\n  margin-top: 3px;\n  border-radius: 50%;\n  background: var(--c-stamp);\n  border: 2px solid var(--c-accent-bright);\n  z-index: 1;\n}\n.empty {\n  padding: 18px 4px 4px;\n  color: var(--c-text-ghost);\n  font-size: 0.76rem;\n  text-align: center;\n}\n.candidate-grid {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 9px;\n  padding-top: 13px;\n}\n.candidate {\n  display: flex;\n  align-items: center;\n  gap: 9px;\n  padding: 10px;\n  border: 1px solid var(--c-border);\n  border-radius: var(--radius-sm);\n  background: rgba(0, 0, 0, 0.22);\n  cursor: pointer;\n  transition: 0.2s ease;\n  &.selected {\n    border-color: var(--c-border-blood);\n    background: rgba(150, 42, 42, 0.11);\n  }\n  &.disabled {\n    opacity: 0.42;\n    cursor: not-allowed;\n  }\n  input {\n    accent-color: var(--c-accent-bright);\n  }\n  select {\n    max-width: 94px;\n    padding: 5px;\n    background: #171310;\n    border: 1px solid var(--c-border);\n    border-radius: 4px;\n    color: var(--c-text-dim);\n    font-size: 0.68rem;\n  }\n}\n.candidate-main {\n  display: flex;\n  flex: 1;\n  min-width: 0;\n  flex-direction: column;\n  gap: 2px;\n  strong {\n    color: var(--c-text);\n    font-size: 0.84rem;\n  }\n  small {\n    color: var(--c-text-faint);\n    white-space: nowrap;\n    overflow: hidden;\n    text-overflow: ellipsis;\n  }\n  em {\n    color: var(--c-bronze-light);\n    font-size: 0.62rem;\n    font-style: normal;\n  }\n}\n.primary-action,\n.seal-action {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 8px;\n  width: 100%;\n  margin-top: 14px;\n  padding: 10px 14px;\n  border: 1px solid var(--c-border-blood);\n  border-radius: var(--radius-sm);\n  background: linear-gradient(145deg, rgba(212, 86, 80, 0.22), rgba(100, 24, 24, 0.4));\n  color: var(--c-text);\n  cursor: pointer;\n  letter-spacing: 0.1em;\n  &:disabled {\n    opacity: 0.45;\n    cursor: wait;\n  }\n}\n.draft-editor {\n  display: flex;\n  flex-direction: column;\n  gap: 12px;\n  padding-top: 16px;\n  margin-top: 14px;\n  border-top: 1px dashed var(--c-border-mid);\n}\n.draft-editor label {\n  display: flex;\n  flex-direction: column;\n  gap: 5px;\n  > span {\n    color: var(--c-text-dim);\n    font-size: 0.78rem;\n  }\n  small {\n    float: right;\n    color: var(--c-text-ghost);\n  }\n}\n.draft-editor input,\n.draft-editor textarea {\n  width: 100%;\n  box-sizing: border-box;\n  padding: 9px 11px;\n  resize: vertical;\n  border: 1px solid var(--c-border);\n  border-radius: var(--radius-sm);\n  background: rgba(0, 0, 0, 0.32);\n  color: var(--c-text);\n  font: inherit;\n  font-size: 0.8rem;\n  line-height: 1.6;\n  outline: none;\n  &:focus {\n 